from datasets import load_from_disk
import numpy as np
from scipy.optimize import curve_fit

ds = load_from_disk('data')
vs = np.array(ds['vocab_size'])
nvp = np.array(ds['non_vocab_parameters'])
D = np.array(ds['num_characters'])
L = np.array(ds['unigram_normalized_loss'])

N0 = np.median(nvp)
D0 = np.median(D)
V0 = np.median(vs)

# Try many forms
forms = []

# Form A: L = E + A/N^alpha + B/D^beta + C/V^gamma
def f_A(N, D, V, E, A, alpha, B, beta, C, gamma):
    return E + A*(N/N0)**(-alpha) + B*(D/D0)**(-beta) + C*(V/V0)**(-gamma)
forms.append(("A: E+A/N^a+B/D^b+C/V^g", f_A, [-4.3, -0.5, 0.3, -1.8, 0.37, -0.5, 0.5]))

# Form B: L = E + A/N^alpha + B/D^beta + C*V^gamma  (V in numerator)
def f_B(N, D, V, E, A, alpha, B, beta, C, gamma):
    return E + A*(N/N0)**(-alpha) + B*(D/D0)**(-beta) + C*(V/V0)**(gamma)
forms.append(("B: E+A/N^a+B/D^b+C*V^g", f_B, [-4.3, -0.5, 0.3, -1.8, 0.37, 0.1, 0.5]))

# Form C: L = E + A/N^alpha + B/D^beta + C*log(V)
def f_C(N, D, V, E, A, alpha, B, beta, C):
    return E + A*(N/N0)**(-alpha) + B*(D/D0)**(-beta) + C*np.log(V/V0)
forms.append(("C: E+A/N^a+B/D^b+C*log(V)", f_C, [-4.3, -0.5, 0.3, -1.8, 0.37, 0.06]))

# Form D: L = E + A/N^alpha + B*V^gamma/D^beta
def f_D(N, D, V, E, A, alpha, B, beta, gamma):
    return E + A*(N/N0)**(-alpha) + B*(D/D0)**(-beta)*(V/V0)**gamma
forms.append(("D: E+A/N^a+B*V^g/D^b", f_D, [-4.3, -0.5, 0.3, -1.8, 0.37, 0.07]))

# Form E: L = E + A/N^alpha + B/(D^beta*N^delta) + C*log(V)
def f_E(N, D, V, E, A, alpha, B, beta, delta, C):
    return E + A*(N/N0)**(-alpha) + B*(D/D0)**(-beta)*(N/N0)**(-delta) + C*np.log(V/V0)
forms.append(("E: E+A/N^a+B/(D^b*N^d)+C*log(V)", f_E, [-4.3, -0.5, 0.3, -1.5, 0.37, 0.1, 0.06]))

# Form F: L = E + A/(N^alpha_N * D^alpha_D) + B*log(V)
def f_F(N, D, V, E, A, alpha_N, alpha_D, B):
    return E + A*(N/N0)**(-alpha_N)*(D/D0)**(-alpha_D) + B*np.log(V/V0)
forms.append(("F: E+A/(N^a*D^b)+B*log(V)", f_F, [-4.3, -1.5, 0.3, 0.37, 0.06]))

# Form G: L = E + A/(N^alpha * D^beta * V^gamma)
def f_G(N, D, V, E, A, alpha, beta, gamma):
    return E + A * (N/N0)**(-alpha) * (D/D0)**(-beta) * (V/V0)**(-gamma)
forms.append(("G: E+A/(N^a*D^b*V^g)", f_G, [-4.3, -1, 0.05, 0.15, 0.02]))

# Form H: L = E + A*N^alpha + B*D^beta + C*V^gamma (power law in numerator)
def f_H(N, D, V, E, A, alpha, B, beta, C, gamma):
    return E + A*(N/N0)**(alpha) + B*(D/D0)**(beta) + C*(V/V0)**(gamma)
forms.append(("H: E+A*N^a+B*D^b+C*V^g", f_H, [-4.3, -0.5, -0.05, -1.5, -0.15, 0.1, 0.02]))

print("Form                             MSE        R²        Params")
print("-" * 75)
for name, func, p0 in forms:
    try:
        popt, _ = curve_fit(
            lambda X, *params: func(X[0], X[1], X[2], *params),
            (nvp, D, vs), L, p0=p0, maxfev=50000
        )
        L_pred = func(nvp, D, vs, *popt)
        r2 = 1 - np.sum((L - L_pred)**2) / np.sum((L - np.mean(L))**2)
        mse = np.mean((L - L_pred)**2)
        param_str = '  '.join([f'{v:.4f}' for v in popt])
        print(f"{name:<32} {mse:.8f}  {r2:.8f}  {param_str}")
    except Exception as e:
        print(f"{name:<32} FAILED: {e}")

